module synchronizer
(
    input clk_a,
    input clk_b,
    input arstn,
    input brstn,
    input [3:0] data_in,
    input data_en,
    output reg [3:0] dataout
);
// -------------------------------------------------------------
// 1. Register to store data_in
// -------------------------------------------------------------
reg [3:0] data_reg;
always @(posedge clk_a or negedge arstn) begin
    if (!arstn) begin
        data_reg <= 4'd0;
    end else begin
        data_reg <= data_in;
    end
end
// -------------------------------------------------------------
// 2. Register to store data_en
// -------------------------------------------------------------
reg data_en_reg;
always @(posedge clk_a or negedge arstn) begin
    if (!arstn) begin
        data_en_reg <= 1'b0;
    end else begin
        data_en_reg <= data_en;
    end
end
// -------------------------------------------------------------
// 3. Registers to store enable signals
// -------------------------------------------------------------
reg en_clap_one, en_clap_two;
always @(posedge clk_b or negedge brstn) begin
    if (!brstn) begin
        en_clap_one <= 1'b0;
        en_clap_two <= 1'b0;
    end else begin
        en_clap_one <= data_en_reg;
        en_clap_two <= en_clap_one;
    end
end
// -------------------------------------------------------------
// 4. Assign output
// -------------------------------------------------------------
always @(posedge clk_b or negedge brstn) begin
    if (!brstn) begin
        dataout <= 4'd0;
    end else begin
        if (en_clap_two) begin
            dataout <= data_reg;
        end else begin
            dataout <= dataout;
        end
    end
end
endmodule
